def solve(track, subTrack):
    # Validate inputs against the contract
    valid_tracks = ['DATA_SCIENCE', 'DEVELOPMENT', 'DESIGN']
    valid_sub_tracks = ['SRM', 'MARATHON', 'CHALLENGE']

    if track not in valid_tracks or subTrack not in valid_sub_tracks:
        return 404  # Not Found

    # Core logic to retrieve distribution data
    distribution_data = {
        'DATA_SCIENCE': {
            'SRM': {'count': 10, 'average': 75},
            'MARATHON': {'count': 5, 'average': 80},
            'CHALLENGE': {'count': 15, 'average': 70},
        },
        'DEVELOPMENT': {
            'SRM': {'count': 8, 'average': 85},
            'MARATHON': {'count': 3, 'average': 90},
            'CHALLENGE': {'count': 12, 'average': 78},
        },
        'DESIGN': {
            'SRM': {'count': 6, 'average': 88},
            'MARATHON': {'count': 4, 'average': 82},
            'CHALLENGE': {'count': 10, 'average': 76},
        },
    }

    # Return the distribution data based on track and subTrack
    return distribution_data.get(track, {}).get(subTrack, 404)

